type ModelId = "kimi-k3" | "claude-fable-5";

async function callModel(modelId: ModelId, prompt: string) {
  const start = Date.now();

  const endpoint =
    modelId === "kimi-k3"
      ? "https://api.moonshot.ai/v1/chat/completions"
      : "https://api.anthropic.com/v1/messages";

  const body =
    modelId === "kimi-k3"
      ? { model: modelId, messages: [{ role: "user", content: prompt }] }
      : { model: modelId, max_tokens: 1000, messages: [{ role: "user", content: prompt }] };

  const res = await fetch(endpoint, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });

  const data = await res.json();
  const elapsedMs = Date.now() - start;

  return { modelId, elapsedMs, data };
}

async function compareModels(prompt: string) {
  const [kimi, fable] = await Promise.all([
    callModel("kimi-k3", prompt),
    callModel("claude-fable-5", prompt),
  ]);

  console.log("Kimi K3:", kimi.elapsedMs, "ms");
  console.log("Fable 5:", fable.elapsedMs, "ms");

  return { kimi, fable };
}
